window.bookSummaryJSON = "<p>Brought to you by Penguin.</p> <p>A shopping mall where droids sell organs harvested from street trash....</p> <p>A murderous imaginary friend....</p> <p>A psychotic composer drafting music from pain....</p> <p>All in a day's work for the Lawman of the Future.</p> <p>Edited by and with an introduction by <i>Dredd </i>veteran Michael Carroll, <i>Judge Fear's Big Day Out and Other Stories </i>gathers the very best short stories from more than a decade of the <i>Judge Dredd Megazine</i>, including stories by legends Alan Grant, Gordon Rennie and Simon Spurrier, among countless others....</p>"; 
